"""Batch translations 101-150 for Distinction III."""

BATCH: dict[int, dict] = {
101: {"nativeDefinition": "To become deeply absorbed in researching or exploring something.", "japaneseMeaning": "（〜の）沼にハマる、深入りする", "etymology": "『不思議の国のアリス』のウサギの穴から、比喩的に深く没頭することを表す。", "examples": {"B": "Netflixで面白いもの探してたら、スポンジ工場のドキュメンタリーに深入りしちゃった。すごく夢中になれる。", "C": "寝る前にWikipediaの沼にハマるの、僕だけ？", "D": "何かに時間をかけすぎて深入りする。"}},
102: {"nativeDefinition": "Unimpressive; mediocre; expressing indifference.", "japaneseMeaning": "まあまあ、イマイチ", "etymology": "meh（うーん）が口語で「どうでもいい・イマイチ」を表す。", "examples": {"B": "隣のカジノで1万ドル当てた人が「まあまあ」って感じだった。喜ばないの？", "C": "最初はこの曲イマイチだったけど、聴けば聴くほど好きになった。", "D": "平凡な。"}},
103: {"nativeDefinition": "To have expert knowledge in one's field.", "japaneseMeaning": "（分野を）よく知っている、詳しい", "etymology": "know one's stuff（自分の分野を知っている）が専門知識を表す。", "examples": {"B": "税理士がいつも「調べて後で連絡します」って言う。本当に詳しいの？", "C": "ゴーイはまだ新人だから、まだ詳しくないのは当然。慣れる時間をあげれば大丈夫。", "D": "自分の分野に専門知識を持つ。"}},
104: {"nativeDefinition": "To make small adjustments or modifications.", "japaneseMeaning": "（〜を）微調整する", "etymology": "tweak（つまむ・微調整する）が細かい修正を表す。", "examples": {"B": "教授はレポートの言い回しを少し直せば完璧だと言った。結局12時間かかった。", "C": "接戦だったけどまた負けた。作戦を微調整しないと。", "D": "何かを少し修正する。"}},
105: {"nativeDefinition": "Secret; kept confidential.", "japaneseMeaning": "内密の、秘密の", "etymology": "hush（静かに）の重複 hush-hush が「秘密にして」という意味。", "examples": {"B": "なんで交際を内密にしようとしてるの？会社の規則に反するの？", "C": "来月異動する予定だけど、まだ未定だから内密にしておいて。", "D": "秘密の。"}},
106: {"nativeDefinition": "To evoke a strong feeling of understanding or connection.", "japaneseMeaning": "（人の）心に響く、共感される", "etymology": "resonate（共鳴する）が心に響くことを比喩的に表す。", "examples": {"B": "彼のTEDトーク、本当に心に響いた。本当の幸せは他人ではなく自分の中にあるって気づいた。", "C": "僕のスピーチ、聴衆の心に響いたと思う？即興だったけど、悪くなかったと思う。", "D": "誰かの心に響く。"}},
107: {"nativeDefinition": "Used when resuming a conversation after an interruption.", "japaneseMeaning": "どこまで話してたっけ", "etymology": "where were we（どこまで話してた？）が会話の再開を促す表現。", "examples": {"B": "どこまで話してたっけ？ああ、ストリートスマートとブックスマートどっちが大事か。", "C": "どこまで話してたっけ？そう、週末に子供たちが何してたか。", "D": "何について話す？"}},
108: {"nativeDefinition": "To increase something.", "japaneseMeaning": "（〜を）引き上げる、増やす", "etymology": "bump up（上にぶつける）が値上げや増加を表す。", "examples": {"B": "いつものカフェ、コーヒーの値段を50セント上げた。悲しい日だ。", "C": "GPAを3.0以上に上げないと留学プログラムに応募できない。", "D": "何かを増やす。"}},
109: {"nativeDefinition": "Clear and sharp in quality (especially sound or image).", "japaneseMeaning": "クリアな、鮮明な", "etymology": "crisp（パリッとした）が音や映像の鮮明さを表す。", "examples": {"B": "このSonyヘッドホン買った。音がすごくクリアで低音も最高。ヘッドホンのゴールドスタンダード。", "C": "想像してみて、澄んだ空気、いい匂い、清々しさ。冬が嫌いな理由が見つからない。", "D": "きれいで明瞭な。"}},
110: {"nativeDefinition": "To make something pointless or counterproductive.", "japaneseMeaning": "（目的を）台無しにする、意味がなくなる", "etymology": "defeat the purpose（目的を打ち負かす）が本末転倒を表す。", "examples": {"B": "顧客の立場に立つことはニーズを把握するプロセスだから、実践しなければ意味がない。", "C": "マスクを顎にかけてるの、明らかに意味ないでしょ？", "D": "何かを無意味にする。"}},
111: {"nativeDefinition": "To confuse or unsettle someone.", "japaneseMeaning": "（人を）混乱させる、戸惑わせる", "etymology": "throw off（外す）が予想外のことで混乱させることを表す。", "examples": {"B": "最初はオーストラリア訛りに戸惑ったけど、今は一番わかりやすい。", "C": "面接が変すぎた。一番混乱したのは「このパンデミックをどう収束させる？」って質問。わかってたらここにいない。", "D": "誰かを混乱させる。"}},
112: {"nativeDefinition": "There is only a small difference between two things.", "japaneseMeaning": "紙一重の差がある", "etymology": "fine line（細い線）が二つの状態の境界が曖昧であることを表す。", "examples": {"B": "天才と狂気は紙一重。同じコインの裏表みたい。", "C": "自信があることと、何でも知ってると思うことは紙一重の差がある。", "D": "二つの間にはわずかな区別がある。"}},
113: {"nativeDefinition": "Also known as (abbreviation: aka).", "japaneseMeaning": "別名、〜として知られる", "etymology": "a.k.a.（also known as＝別名）の略。", "examples": {"B": "久保、別名日本のメッシが素晴らしいゴール決めた。壮観だった。", "C": "ここが僕の聖域、別名寝室。かっこいいでしょ？", "D": "別名。"}},
114: {"nativeDefinition": "Unchanged; in its current state.", "japaneseMeaning": "そのまま、現状のまま", "etymology": "as is（あるがままに）が変更なしの状態を表す。", "examples": {"B": "エッセイのこの部分書き直そうかと思ったけど、そのままにしよう。", "C": "なんでそんな完璧主義なの？レポートはそのままで十分。車輪の再発明は不要。", "D": "変更なし。"}},
115: {"nativeDefinition": "To be unrealistic or not paying attention to reality.", "japaneseMeaning": "夢見がちな、現実を見ていない", "etymology": "head in the clouds（頭が雲の中）が空想にふけっている状態を表す。", "examples": {"B": "エマと話したいけど、今は夢見がちみたい。また今度。", "C": "テリーの仕事はいつも確認する。いつも現実を見てないみたいだから。", "D": "非現実的な。"}},
116: {"nativeDefinition": "Good value for the money spent.", "japaneseMeaning": "コスパがいい", "etymology": "bang for the buck（ドルの価値に対するインパクト）が費用対効果を表す。", "examples": {"B": "ホテルよりAirbnb使った方がいいよ。コスパがいい。", "C": "コスパ最高のMacBookはどれ？モデル多すぎて選びにくい。", "D": "費用対効果。"}},
117: {"nativeDefinition": "To trap someone in a situation they cannot escape.", "japaneseMeaning": "（人を）追い詰める", "etymology": "corner（角）が比喩的に逃げ場のない状況に追い込むことを表す。", "examples": {"B": "母が今朝電話してきて、宿題終わるまで外で遊ぶなって。", "C": "上司が常に監視してる。やめてほしい。追い詰められた感じ。", "D": "誰かを逃げられない状況に追い込む。"}},
118: {"nativeDefinition": "To criticize or blame oneself excessively.", "japaneseMeaning": "（自分を）責めすぎる", "etymology": "beat oneself up（自分を殴る）が過度な自責を比喩的に表す。", "examples": {"B": "大学中退のこと、少し自分を責めてる。でも済んだことは仕方ない。", "C": "コントロールできないことで自分を責めるのはやめなきゃ。", "D": "自分を批判する。"}},
119: {"nativeDefinition": "Before someone was born or started a particular period.", "japaneseMeaning": "（人が）生まれる前の時代、知らない時代", "etymology": "before one's time（自分の時代より前）が経験していない時代を表す。", "examples": {"B": "この曲、僕が生まれる前の時代だけど、すごくいい。好き。", "C": "僕がここに来る前に同じ名前の人がいたって聞いた。本当？", "D": "誰かが生まれる前、働き始める前。"}},
120: {"nativeDefinition": "A large amount of money.", "japaneseMeaning": "大金、たくさんのお金", "etymology": "big（大きい）＋bucks（ドル）が口語で大金を表す。", "examples": {"B": "一歩下がって考えて。なんで他人のために大金を稼ぐために必死なの？ピーナッツしかもらえないのに。", "C": "彼、今大金稼いでるのはわかるけど、全部払わせるのはフェアじゃない。割り勘しよう。", "D": "たくさんのお金。"}},
121: {"nativeDefinition": "A famous or well-known person, brand, or organization.", "japaneseMeaning": "大物、有名ブランド", "etymology": "big name（大きな名前）が著名人・有名企業を表す。", "examples": {"B": "思い出して。F1の大物だと思うけど、名前が出てこない。", "C": "このプロジェクトに関わる大物見て。KPMG、デロイト、アクセンチュア。絶対成功する。", "D": "有名な人や会社。"}},
122: {"nativeDefinition": "Through people telling each other informally.", "japaneseMeaning": "口コミで", "etymology": "word of mouth（口から口へ）が口コミによる伝播を表す。", "examples": {"B": "このバーは口コミで知った。地元の人だけが知る隠れた名店。", "C": "これ自体がすごく良い商品だから、口コミで自然に広がると思う。", "D": "人々が話すことによって。"}},
123: {"nativeDefinition": "In defense of someone; speaking on their behalf.", "japaneseMeaning": "（人の）代弁をすると言えば", "etymology": "in one's defense（誰かの防御として）が擁護の意味。", "examples": {"B": "靴を傷つけてごめん。でも彼の代弁をすると、職場で高いもの履くべきじゃない。", "C": "シャノンが昨日怒鳴ったって聞いた。彼女らしくない。何かあったのかも。", "D": "誰かを支持する。"}},
124: {"nativeDefinition": "To fit something into a busy schedule.", "japaneseMeaning": "（予定に）押し込む、時間を作る", "etymology": "squeeze in（押し込む）が忙しい中で時間を確保することを表す。", "examples": {"B": "歯が痛すぎる。でも歯医者は来週まで時間作ってくれない。耐えるしかない。", "C": "毎朝仕事前にワークアウトを時間に押し込もうとしてるけど、うまくいかない日もある。", "D": "何かの時間を作る。"}},
125: {"nativeDefinition": "The problem is solved; issue resolved.", "japaneseMeaning": "問題解決、これで解決", "etymology": "problem solved（問題解決）が簡単な解決策を示す。", "examples": {"B": "交通事故が怖いなら、車を運転しなければいい。問題解決。", "C": "テストまた0点。母に見せたら殺される。とりあえず隠す。問題解決。", "D": "問題は解決された。"}},
126: {"nativeDefinition": "Making everyone feel included and welcome.", "japaneseMeaning": "包括的な、誰も排除しない", "etymology": "inclusive（包含的な）が多様性を受け入れることを表す。", "examples": {"B": "同僚がもっと包括的になろうとしてる。僕がシャイだと思ってるけど、大人数が苦手なだけ。", "C": "友達はみんな包括的だから、心配しないで。", "D": "積極的に友好的な。"}},
127: {"nativeDefinition": "A public acknowledgment or mention of praise.", "japaneseMeaning": "シャウトアウト、紹介・称賛", "etymology": "shout out（叫び）が公の場での紹介・称賛を表す。", "examples": {"B": "この本に関わったみんなに大きなシャウトアウトを。", "C": "彼女の好きな俳優が昨夜YouTubeライブで彼女にシャウトアウトして、めちゃくちゃ喜んでた。", "D": "クレジット、言及。"}},
128: {"nativeDefinition": "The basic characteristics shared by all humans.", "japaneseMeaning": "人間性、人間の本性", "etymology": "human nature（人間の性質）が生来の性向を表す。", "examples": {"B": "落ち込まないで。物事を忘れるのは人間性だよ。簡単におさらいするね。", "C": "人間性は基本的に善か悪か、どう思う？", "D": "生来の人間の行動。"}},
129: {"nativeDefinition": "Characteristic or most representative of a brand or person.", "japaneseMeaning": "代名詞的な、看板の", "etymology": "signature（署名）が特徴的なスタイルや商品を表す。", "examples": {"B": "ルイ・ヴィトンの代名詞的モノグラム、実はルイ・ヴィトンの息子がデザインしたんだ。", "C": "このトラベルヌードルを注文する。看板メニューだから。", "D": "最もよく知られている。"}},
130: {"nativeDefinition": "To join a conversation by adding a comment.", "japaneseMeaning": "（会話に）口を挟む、加わる", "etymology": "chime in（鐘が鳴る）が会話に割り込むことを表す。", "examples": {"B": "何の話かわからないのに口を挟めないよ。", "C": "言いたいこと全部は覚えられないから、会議中に漏れたら口を挟んで。", "D": "会話に割り込む。"}},
131: {"nativeDefinition": "Excitement and attention surrounding something.", "japaneseMeaning": "話題性、盛り上がり", "etymology": "hype（誇大宣伝）が過度の期待や注目を表す。", "examples": {"B": "この映画、過大評価だと思う。なんでこんなに話題になってるのかわからない。", "C": "このバー行きたいけど、話題性が高すぎる。落ち着いてから行こう。", "D": "興奮と注目。"}},
132: {"nativeDefinition": "To improve the overall quality standard.", "japaneseMeaning": "（基準・レベルを）引き上げる", "etymology": "raise the standard（基準を上げる）が品質向上を表す。", "examples": {"B": "新マネージャーがクラブのレベルを引き上げて、選手全員のベストを引き出した。", "C": "オンライン英会話を義務教育に組み込めば、国の英語レベルは確実に引き上がる。", "D": "全体的な品質レベルを上げる。"}},
133: {"nativeDefinition": "At most; no more than (informal).", "japaneseMeaning": "せいぜい、最大で", "etymology": "tops（頂点）が「最大で」という上限を表す。", "examples": {"B": "Tシャツ200ドル？高すぎ。50ドルがせいぜい。すぐダメになるし。", "C": "iPhone 6のバッテリーがダメ。せいぞい2時間持つ。MacBookもそろそろダメかも。", "D": "最大で。"}},
134: {"nativeDefinition": "Pay attention and listen carefully.", "japaneseMeaning": "ちょっと聞いて、注意して", "etymology": "listen up（聞き上げる）が注意を促す口語表現。", "examples": {"B": "みんな、ちょっと聞いて。すぐボール蹴りたいのはわかるけど、先に安全について話さないと。", "C": "ここちょっと聞いて。このコースは初心者向けだから、中級以上は受講しないでね。", "D": "注意して聞く。"}},
135: {"nativeDefinition": "Difficult to understand someone's intentions or feelings.", "japaneseMeaning": "読めない、わかりにくい", "etymology": "hard to read（読みにくい）が人の本心が見えないことを表す。", "examples": {"B": "彼女、本当に読めない。毎日メッセージくれるのに、デートに誘うと断られる。", "C": "上司は読めないから、常に油断ができない。", "D": "理解するのが難しい。"}},
136: {"nativeDefinition": "Willing to consider new ideas and perspectives.", "japaneseMeaning": "オープンマインドな、偏見がない", "etymology": "open-minded（心が開いている）が柔軟な思考を表す。", "examples": {"B": "カイリー、オープンマインドな人だと思う？お腹に巨大ミッキーのタトゥー入れるって言った時、何も言わなかったし。", "C": "彼が成功してる理由は、本当にオープンマインドだから。人の話をちゃんと聞く。", "D": "偏見がなく新しい考えを受け入れる。"}},
137: {"nativeDefinition": "To ignore or shut out distractions.", "japaneseMeaning": "（〜を）シャットアウトする、無視する", "etymology": "block out（遮る）が邪魔を排除することを表す。", "examples": {"B": "インフルエンサーになるなら、ヘイターをシャットアウトするのが上手くならないと。", "C": "この邪魔を全部シャットアウトする最善の方法は？来週の試験の勉強が本当に必要なんだ。", "D": "何かを無視する。"}},
138: {"nativeDefinition": "To reveal how old someone is through their behavior.", "japaneseMeaning": "（人の）年齢がバレる", "etymology": "show one's age（年齢を見せる）が世代がわかる行動を表す。", "examples": {"B": "絵文字使いすぎると年齢バレるのはわかってる。でも止められない。", "C": "今日、ポケモン赤が初めてプレイしたゲームだって言って年齢バレた。", "D": "誰かの年齢がわかる。"}},
139: {"nativeDefinition": "Someone who gets upset when they lose.", "japaneseMeaning": "負けず嫌い、負け方が悪い人", "etymology": "sore loser（痛い負け方をする人）が負けを認めない人を表す。", "examples": {"B": "負けそうになるたびにログアウトする。本当に負けず嫌い。", "C": "ポールは最大の負けず嫌い。先週テニスで負けたから今も話してくれない。", "D": "負けると upset になる人。"}},
140: {"nativeDefinition": "Go ahead; start (used to encourage someone to begin).", "japaneseMeaning": "どうぞ、遠慮なく", "etymology": "fire away（撃ち放て）が「遠慮なく始めて」という意味に使われる。", "examples": {"B": "質問ある？ノート取るからちょっと待って。OK、どうぞ。", "C": "言いたいことがあるって？どうぞ。", "D": "どうぞ。"}},
141: {"nativeDefinition": "To become addicted to or obsessed with something.", "japaneseMeaning": "（〜に）ハマる、夢中になる", "etymology": "hooked on（引っかかっている）が中毒的な没頭を表す。", "examples": {"B": "この漫画に数週間ハマってる。悪いほど面白い。", "C": "閉じ込められ症候群になって散歩に出たら、送ってくれたポッドキャスト聴き始めた。完全にハマってる。", "D": "何かに夢中になる。"}},
142: {"nativeDefinition": "Intentionally planned as part of a scheme.", "japaneseMeaning": "計画の一部、意図的な", "etymology": "part of the plan（計画の一部）が意図された出来事を表す。", "examples": {"B": "Google Mapsが逆方向に進んでるって言うのは計画の一部？", "C": "サプライズバースデーケーキは計画の一部？それともレストランが勝手に？", "D": "意図的な。"}},
143: {"nativeDefinition": "To cancel something that was planned.", "japaneseMeaning": "（〜を）中止する", "etymology": "call off（呼び止める）が予定をキャンセルすることを表す。", "examples": {"B": "出席者が少なそう。今日のワークショップ中止にならないといいけど。", "C": "ピクニック中止にしよう。天気最悪だし、そもそもピクニック嫌いだし。", "D": "何かをキャンセルする。"}},
144: {"nativeDefinition": "Ready whenever the other person is ready.", "japaneseMeaning": "準備できてるよ、いつでも", "etymology": "ready when you are（あなたの準備ができたら）が相手のタイミングに合わせる表現。", "examples": {"B": "電話したいタイミング教えて。いつでも準備できてる。", "C": "いつでも準備OK。出発したくなったら声かけて。", "D": "今すぐ準備できている。"}},
145: {"nativeDefinition": "OK; alright (informal, cheerful).", "japaneseMeaning": "オッケー、了解", "etymology": "okey-dokey（OKの冗談めいた言い方）が軽い同意を表す。", "examples": {"B": "面白い話があるの？オッケー、オッケー、聞いてるよ。", "C": "金曜6時頃仕事終わる？オッケー、終わったら連絡して迎えに行く。あとは臨機応変で。", "D": "OK。"}},
146: {"nativeDefinition": "For an unknown or unspecified reason.", "japaneseMeaning": "なぜか、理由はわからないけど", "etymology": "for whatever reason（どんな理由であれ）が原因不明を表す。", "examples": {"B": "トーマス、来週ニュージーランド旅行の予定だったのに、なぜか180度考えを変えた。", "C": "なぜかボリスがダサい髪型の代名詞になった。僕はかっこいいと思うけど。", "D": "説明なしに。"}},
147: {"nativeDefinition": "I thought; I assumed.", "japaneseMeaning": "〜だと思った、〜だろうと思った", "etymology": "I figured（計算した＝推測した）が推量を表す口語。", "examples": {"B": "メッセージ無視してごめん。忙しいんだろうと思った。", "C": "ハリケーン・マラコムの本読んだことなかったから、そろそろ読もうと思った。", "D": "私は思った。"}},
148: {"nativeDefinition": "Very popular and fashionable at the moment.", "japaneseMeaning": "大流行の、今のトレンド", "etymology": "all the rage（全ての怒り→全ての熱狂）が大流行を表す。", "examples": {"B": "韓国ものが今大流行。何がそんなにすごいのかわからない。", "C": "暗号通貨が今大流行だけど、簡単に儲けられる余地はもうないと思う。", "D": "とても人気でトレンディな。"}},
149: {"nativeDefinition": "Online content designed to attract clicks through sensationalism.", "japaneseMeaning": "クリックベイト、釣りタイトル", "etymology": "click（クリック）＋bait（餌）で、クリックを釣るコンテンツを表す。", "examples": {"B": "このニュースサイト二度と行かない。クリックベイト記事ばかり。", "C": "本物の動画だと思ったら、クリックベイトだった。", "D": "注目を集める欺瞞的なもの。"}},
150: {"nativeDefinition": "A silly or unintelligent person.", "japaneseMeaning": "空っぽな人、天然", "etymology": "airhead（空気の頭）が頭の中身がない人を表す俗語。", "examples": {"B": "仮に言うと、頭が空っぽな金持ちと貧しいけど賢い人、どっちを彼氏に選ぶ？", "C": "ジョアン、本当に天然だね。また添付ファイル忘れた。", "D": "バカな人。"}},
}
